static uint64
linux_argraw(int n)
{
  struct proc *p = myproc();

  switch (n) {
  case 0:
    return p->trapframe->a0;
  case 1:
    return p->trapframe->a1;
  case 2:
    return p->trapframe->a2;
  case 3:
    return p->trapframe->a3;
  case 4:
    return p->trapframe->a4;
  case 5:
    return p->trapframe->a5;
  }
  panic("linux_argraw");
  return 0;
}

static int
linux_console_write(uint64 src, int n)
{
  char buf[64];
  int done = 0;

  while (done < n) {
    int take = sizeof(buf);
    if (take > n - done)
      take = n - done;
    if (copyin(myproc()->pagetable, buf, src + done, take) < 0)
      break;
    push_off();
    for (int i = 0; i < take; i++)
      consputc(buf[i]);
    pop_off();
    done += take;
  }
  return done;
}

static int
linux_copyout_zeros(uint64 dst, uint n)
{
  char zeros[64];
  uint done = 0;

  memset(zeros, 0, sizeof(zeros));
  while (done < n) {
    uint take = n - done;
    if (take > sizeof(zeros))
      take = sizeof(zeros);
    if (copyout(myproc()->pagetable, dst + done, zeros, take) < 0)
      return -LINUX_EFAULT;
    done += take;
  }
  return n;
}

static uint64
linux_sys_write(void)
{
  int fd = (int)linux_argraw(0);
  uint64 src = linux_argraw(1);
  uint64 n = linux_argraw(2);

  if (n > (1 << 20))
    return -LINUX_EINVAL;

  struct linux_fd *lfd = linux_fd_get(fd);
  if (lfd == 0) {
    if (fd == 1 || fd == 2)
      return linux_console_write(src, (int)n);
    return -LINUX_EBADF;
  }
  if (!lfd->writable)
    return -LINUX_EBADF;
  if (lfd->type == LINUX_FD_CONSOLE)
    return linux_console_write(src, (int)n);
  if (lfd->type == LINUX_FD_PIPE) {
    int r = filewrite(lfd->xv6_file, src, (int)n);
    return r < 0 ? -LINUX_EIO : r;
  }
  if (lfd->type != LINUX_FD_TMP_FILE)
    return -LINUX_EBADF;

  struct linux_tmp_path *tmp = linux_tmp_get(lfd->tmp_index);
  if (tmp == 0 || tmp->is_dir)
    return -LINUX_EBADF;
  if (lfd->off > LINUX_TMP_FILE_BYTES ||
      n > LINUX_TMP_FILE_BYTES - lfd->off)
    return -LINUX_ENOMEM;
  if (copyin(myproc()->pagetable, (char *)tmp->data + lfd->off, src, n) < 0)
    return -LINUX_EFAULT;
  lfd->off += n;
  if (tmp->size < lfd->off)
    tmp->size = lfd->off;
  return n;
}

