#define ELF_TYPE_EXEC       2
#define ELF_TYPE_DYN        3
#define ELF_MACHINE_RISCV   243
#define ELF_PROG_INTERP     3
#define LINUX_BASIC_HEAP_GAP_SIZE (1024 * 1024)
#define LINUX_BUSYBOX_HEAP_GAP_SIZE (16 * 1024 * 1024)
#define LINUX_A4_HEAP_GAP_SIZE (32 * 1024 * 1024)
#define LINUX_MAX_ARGC      8
#define LINUX_MAX_ARG_BYTES 64
#define LINUX_USERSTACK_PAGES 16

#define AT_NULL   0
#define AT_PHENT  4
#define AT_PHNUM  5
#define AT_PAGESZ 6
#define AT_ENTRY  9
#define AT_UID    11
#define AT_EUID   12
#define AT_GID    13
#define AT_EGID   14
#define AT_SECURE 23

#define LINUX_MUSL_DEFAULT_PATH  "PATH=/musl:/bin:/usr/bin:."
#define LINUX_GLIBC_DEFAULT_PATH "PATH=/glibc:/bin:/usr/bin:."

struct linux_exec_args {
  int argc;
  char argv[LINUX_MAX_ARGC][LINUX_MAX_ARG_BYTES];
};

static int
linux_flags2perm(int flags)
{
  int perm = 0;

  if (flags & ELF_PROG_FLAG_EXEC)
    perm |= PTE_X;
  if (flags & ELF_PROG_FLAG_WRITE)
    perm |= PTE_W;
  return perm;
}

static int
loadseg_ext4(pagetable_t pagetable, uint64 va, char *path, uint offset, uint sz)
{
  uint done = 0;

  while (done < sz) {
    uint64 dstva = va + done;
    uint64 pa = walkaddr(pagetable, dstva);
    if (pa == 0)
      panic("loadseg_ext4: address should exist");

    uint pageoff = dstva % PGSIZE;
    uint n = PGSIZE - pageoff;
    if (n > sz - done)
      n = sz - done;

    if (ext4_lite_read_file(path, offset + done, (void *)(pa + pageoff), n) != n)
      return -1;
    done += n;
  }

  return 0;
}

static void
linux_free_vmas(pagetable_t pagetable, struct linux_vma *vmas)
{
  for (int i = 0; i < LINUX_MAX_VMA; i++) {
    if (vmas[i].used && vmas[i].len > 0)
      uvmunmap(pagetable, vmas[i].addr, vmas[i].len / PGSIZE, 1);
    memset(&vmas[i], 0, sizeof(vmas[i]));
  }
}

static int
linux_role_is_busybox(int role)
{
  return role == CONTEST_ROLE_BUSYBOX_MUSL ||
         role == CONTEST_ROLE_BUSYBOX_GLIBC;
}

static int
linux_role_is_contest_linux(int role)
{
  return role == CONTEST_ROLE_BASIC_MUSL ||
         linux_role_is_busybox(role) ||
         role == CONTEST_ROLE_LIBCTEST_MUSL ||
         role == CONTEST_ROLE_LIBCTEST_DYNAMIC_MUSL ||
         role == CONTEST_ROLE_LUA_MUSL;
}

static char *
linux_role_default_env(int role)
{
  if (role == CONTEST_ROLE_BUSYBOX_GLIBC)
    return LINUX_GLIBC_DEFAULT_PATH;
  return LINUX_MUSL_DEFAULT_PATH;
}

static int
linux_role_preserves_runtime(int role)
{
  return linux_role_is_busybox(role) ||
         role == CONTEST_ROLE_LUA_MUSL;
}

static void
linux_init_default_fds(struct proc *p, int role)
{
  proc_close_linux_fds(p);
  memset(p->linux_fds, 0, sizeof(p->linux_fds));
  if (!linux_role_preserves_runtime(role))
    memset(p->linux_tmp_paths, 0, sizeof(p->linux_tmp_paths));
  memset(p->linux_vmas, 0, sizeof(p->linux_vmas));
  memset(p->linux_mounts, 0, sizeof(p->linux_mounts));
  for (int i = 0; i < 3; i++) {
    p->linux_fds[i].used = 1;
    p->linux_fds[i].type = LINUX_FD_CONSOLE;
    p->linux_fds[i].readable = i == 0;
    p->linux_fds[i].writable = i != 0;
  }
  if (role == CONTEST_ROLE_BUSYBOX_GLIBC)
    safestrcpy(p->linux_cwd, "/glibc", sizeof(p->linux_cwd));
  else if (role == CONTEST_ROLE_BUSYBOX_MUSL ||
           role == CONTEST_ROLE_LIBCTEST_MUSL ||
      role == CONTEST_ROLE_LIBCTEST_DYNAMIC_MUSL ||
      role == CONTEST_ROLE_LUA_MUSL)
    safestrcpy(p->linux_cwd, "/musl", sizeof(p->linux_cwd));
  else
    safestrcpy(p->linux_cwd, "/musl/basic", sizeof(p->linux_cwd));
}

static char *
linux_basename(char *path)
{
  char *base = path;

  for (char *p = path; *p; p++) {
    if (*p == '/' && p[1])
      base = p + 1;
  }

  return base;
}

static int
collect_linux_exec_args(char *path, char **argv, struct linux_exec_args *args)
{
  memset(args, 0, sizeof(*args));

  if (argv == 0 || argv[0] == 0) {
    safestrcpy(args->argv[0], linux_basename(path), LINUX_MAX_ARG_BYTES);
    if (args->argv[0][0] == 0)
      return -1;
    args->argc = 1;
    return 0;
  }

  for (int i = 0; i < LINUX_MAX_ARGC; i++) {
    if (argv[i] == 0) {
      args->argc = i;
      return args->argc > 0 ? 0 : -1;
    }

    if (strlen(argv[i]) >= LINUX_MAX_ARG_BYTES)
      return -1;
    safestrcpy(args->argv[i], argv[i], LINUX_MAX_ARG_BYTES);
  }

  if (argv[LINUX_MAX_ARGC] != 0)
    return -1;
  args->argc = LINUX_MAX_ARGC;
  return 0;
}

static int
push_linux_initial_stack(pagetable_t pagetable, uint64 stackbase, uint64 stacktop,
                         char *path, char **argv, struct elfhdr *elf, int role,
                         uint64 *sp_out)
{
  uint64 sp = stacktop;
  uint64 argv_addrs[LINUX_MAX_ARGC];
  uint64 env_addr = 0;
  char *env = linux_role_default_env(role);
  struct linux_exec_args args;
  uint64 auxv[] = {
    AT_PAGESZ, PGSIZE,
    AT_PHENT, sizeof(struct proghdr),
    AT_PHNUM, elf->phnum,
    AT_ENTRY, elf->entry,
    AT_UID, 0,
    AT_EUID, 0,
    AT_GID, 0,
    AT_EGID, 0,
    AT_SECURE, 0,
    AT_NULL, 0,
  };
  uint64 words[1 + LINUX_MAX_ARGC + 1 + 1 + 1 +
               sizeof(auxv) / sizeof(auxv[0])];
  int n = 0;

  if (collect_linux_exec_args(path, argv, &args) < 0)
    return -1;

  for (int i = args.argc - 1; i >= 0; i--) {
    int len = strlen(args.argv[i]) + 1;
    sp -= len;
    if (sp < stackbase)
      return -1;
    if (copyout(pagetable, sp, args.argv[i], len) < 0)
      return -1;
    argv_addrs[i] = sp;
  }

  int env_len = strlen(env) + 1;
  sp -= env_len;
  if (sp < stackbase)
    return -1;
  if (copyout(pagetable, sp, env, env_len) < 0)
    return -1;
  env_addr = sp;

  sp -= sp % 16;
  words[n++] = args.argc;
  for (int i = 0; i < args.argc; i++)
    words[n++] = argv_addrs[i];
  words[n++] = 0;
  words[n++] = env_addr;
  words[n++] = 0;
  for (int i = 0; i < sizeof(auxv) / sizeof(auxv[0]); i++)
    words[n++] = auxv[i];

  sp -= n * sizeof(uint64);
  sp -= sp % 16;
  if (sp < stackbase)
    return -1;
  if (copyout(pagetable, sp, (char *)words, n * sizeof(uint64)) < 0)
    return -1;

  *sp_out = sp;
  return 0;
}

