#define EXT4_SUPER_OFFSET      1024
#define EXT4_SUPER_MAGIC       0xef53
#define EXT4_EXTENT_MAGIC      0xf30a
#define EXT4_N_BLOCK_BYTES     60
#define EXT4_ROOT_INO          2
#define EXT4_S_IFMT            0170000
#define EXT4_S_IFDIR           0040000
#define EXT4_S_IFREG           0100000
#define EXT4_EXTENTS_FL        0x80000
#define EXT4_MAX_NAME_LEN      255
#define EXT4_MIN_BLOCK_SIZE    1024

struct ext4_lite_state {
  int mounted;
  uint block_size;
  uint blocks_per_group;
  uint inodes_per_group;
  uint inode_size;
  uint desc_size;
  uint first_data_block;
  uint feature_compat;
  uint feature_incompat;
  uint feature_ro_compat;
};

static struct ext4_lite_state ext4;

static uint16
get16(const uchar *p)
{
  return p[0] | ((uint16)p[1] << 8);
}

static uint32
get32(const uchar *p)
{
  return (uint32)p[0] | ((uint32)p[1] << 8) | ((uint32)p[2] << 16) |
         ((uint32)p[3] << 24);
}

static uint64
get64lohi(uint32 lo, uint32 hi)
{
  return (uint64)lo | ((uint64)hi << 32);
}

static uint
umin(uint a, uint b)
{
  return a < b ? a : b;
}

static int
ext4_read_block(uint64 blockno, uchar *dst)
{
  if (ext4.block_size != 4096)
    return -1;

  for (uint i = 0; i < ext4.block_size / BSIZE; i++) {
    struct buf *bp = bread(ROOTDEV, (uint)(blockno * (ext4.block_size / BSIZE) + i));
    memmove(dst + i * BSIZE, bp->data, BSIZE);
    brelse(bp);
  }

  return 0;
}

static int
ext4_mount(void)
{
  if (ext4.mounted)
    return 0;

  struct buf *bp = bread(ROOTDEV, EXT4_SUPER_OFFSET / BSIZE);
  uchar *sb = (uchar *)bp->data + (EXT4_SUPER_OFFSET % BSIZE);

  uint16 magic = get16(sb + 0x38);
  if (magic != EXT4_SUPER_MAGIC) {
    brelse(bp);
    printf("ext4: bad magic 0x%x\n", magic);
    return -1;
  }

  uint log_block_size = get32(sb + 0x18);
  if (log_block_size > 2) {
    brelse(bp);
    printf("ext4: unsupported log_block_size=%u\n", log_block_size);
    return -1;
  }

  ext4.block_size = EXT4_MIN_BLOCK_SIZE << log_block_size;
  ext4.blocks_per_group = get32(sb + 0x20);
  ext4.inodes_per_group = get32(sb + 0x28);
  ext4.first_data_block = get32(sb + 0x14);
  ext4.inode_size = get16(sb + 0x58);
  ext4.feature_compat = get32(sb + 0x5c);
  ext4.feature_incompat = get32(sb + 0x60);
  ext4.feature_ro_compat = get32(sb + 0x64);
  ext4.desc_size = get16(sb + 0xfe);
  if (ext4.desc_size == 0)
    ext4.desc_size = 32;

  brelse(bp);

  if (ext4.block_size != 4096 || ext4.inode_size != 256 ||
      ext4.blocks_per_group == 0 || ext4.inodes_per_group == 0 ||
      ext4.desc_size < 32) {
    printf("ext4: unsupported layout block_size=%u inode_size=%u desc_size=%u\n",
           ext4.block_size, ext4.inode_size, ext4.desc_size);
    return -1;
  }

  ext4.mounted = 1;
  printf("ext4: magic=0x%x block_size=%u inode_size=%u features compat=0x%x incompat=0x%x ro=0x%x\n",
         EXT4_SUPER_MAGIC, ext4.block_size, ext4.inode_size,
         ext4.feature_compat, ext4.feature_incompat, ext4.feature_ro_compat);
  return 0;
}

static uint64
ext4_gdt_start_block(void)
{
  if (ext4.block_size == 1024)
    return 2;
  return 1;
}

static int
ext4_inode_table_block(uint group, uint64 *out)
{
  uchar *block = kalloc();
  if (block == 0)
    return -1;

  uint64 desc_offset = (uint64)group * ext4.desc_size;
  uint64 blockno = ext4_gdt_start_block() + desc_offset / ext4.block_size;
  uint inblock = desc_offset % ext4.block_size;
  if (inblock + 32 > ext4.block_size) {
    kfree(block);
    return -1;
  }

  if (ext4_read_block(blockno, block) < 0) {
    kfree(block);
    return -1;
  }

  uchar *gd = block + inblock;
  uint32 lo = get32(gd + 0x08);
  uint32 hi = 0;
  if (ext4.desc_size >= 64)
    hi = get32(gd + 0x28);
  *out = get64lohi(lo, hi);

  kfree(block);
  return 0;
}

static int
ext4_read_inode(uint inum, struct ext4_lite_inode *out)
{
  if (inum == 0 || ext4_mount() < 0)
    return -1;

  uint group = (inum - 1) / ext4.inodes_per_group;
  uint index = (inum - 1) % ext4.inodes_per_group;
  uint64 inode_table;
  if (ext4_inode_table_block(group, &inode_table) < 0)
    return -1;

  uint64 inode_offset = (uint64)index * ext4.inode_size;
  uint64 blockno = inode_table + inode_offset / ext4.block_size;
  uint inblock = inode_offset % ext4.block_size;
  if (inblock + ext4.inode_size > ext4.block_size)
    return -1;

  uchar *block = kalloc();
  if (block == 0)
    return -1;
  if (ext4_read_block(blockno, block) < 0) {
    kfree(block);
    return -1;
  }

  uchar *ino = block + inblock;
  out->inum = inum;
  out->mode = get16(ino + 0x00);
  out->nlink = get16(ino + 0x1a);
  out->flags = get32(ino + 0x20);
  out->size = get64lohi(get32(ino + 0x04), get32(ino + 0x6c));
  memmove(out->block, ino + 0x28, EXT4_N_BLOCK_BYTES);

  kfree(block);
  return 0;
}

static int
ext4_extent_map_node(const uchar *node, uint logical, uint64 *physical)
{
  uint16 magic = get16(node + 0x00);
  uint16 entries = get16(node + 0x02);
  uint16 max = get16(node + 0x04);
  uint16 depth = get16(node + 0x06);

  if (magic != EXT4_EXTENT_MAGIC || entries > max)
    return -1;

  if (depth == 0) {
    for (uint i = 0; i < entries; i++) {
      const uchar *ex = node + 12 + i * 12;
      uint first = get32(ex + 0x00);
      uint len = get16(ex + 0x04) & 0x7fff;
      uint64 start = get64lohi(get32(ex + 0x08), get16(ex + 0x06));
      if (logical >= first && logical < first + len) {
        *physical = start + (logical - first);
        return 0;
      }
    }
    return -1;
  }

  const uchar *chosen = 0;
  for (uint i = 0; i < entries; i++) {
    const uchar *idx = node + 12 + i * 12;
    uint first = get32(idx + 0x00);
    if (logical >= first)
      chosen = idx;
    else
      break;
  }
  if (chosen == 0)
    return -1;

  uint64 leaf = get64lohi(get32(chosen + 0x04), get16(chosen + 0x08));
  uchar *block = kalloc();
  if (block == 0)
    return -1;
  int rc = -1;
  if (ext4_read_block(leaf, block) == 0)
    rc = ext4_extent_map_node(block, logical, physical);
  kfree(block);
  return rc;
}

static int
ext4_read_inode_block(const struct ext4_lite_inode *ino, uint logical,
                      uchar *dst)
{
  if ((ino->flags & EXT4_EXTENTS_FL) == 0)
    return -1;

  uint64 physical;
  if (ext4_extent_map_node(ino->block, logical, &physical) < 0)
    return -1;
  return ext4_read_block(physical, dst);
}

int
ext4_read_inode_data(const struct ext4_lite_inode *ino, uint off, void *dst,
                     uint n)
{
  if (off >= ino->size)
    return 0;
  if ((uint64)off + n > ino->size)
    n = (uint)(ino->size - off);

  uchar *block = kalloc();
  if (block == 0)
    return -1;

  uint done = 0;
  while (done < n) {
    uint pos = off + done;
    uint logical = pos / ext4.block_size;
    uint inblock = pos % ext4.block_size;
    uint take = umin(n - done, ext4.block_size - inblock);
    if (ext4_read_inode_block(ino, logical, block) < 0) {
      kfree(block);
      return -1;
    }
    memmove((uchar *)dst + done, block + inblock, take);
    done += take;
  }

  kfree(block);
  return done;
}

int
ext4_lite_inode_type(const struct ext4_lite_inode *ino)
{
  if ((ino->mode & EXT4_S_IFMT) == EXT4_S_IFDIR)
    return EXT4_LITE_TYPE_DIR;
  if ((ino->mode & EXT4_S_IFMT) == EXT4_S_IFREG)
    return EXT4_LITE_TYPE_REG;
  return -1;
}

int
ext4_lite_read_inode_data(const struct ext4_lite_inode *ino, uint off,
                          void *dst, uint n)
{
  return ext4_read_inode_data(ino, off, dst, n);
}

