static int
kfork_internal(uint64 child_stack)
{
  int i, pid;
  struct proc *np;
  struct proc *p = myproc();

  // Allocate process.
  if ((np = allocproc()) == 0) {
    return -1;
  }

  // Copy user memory from parent to child.
  if (uvmcopy(p->pagetable, np->pagetable, p->sz) < 0) {
    freeproc(np);
    release(&np->lock);
    return -1;
  }
  np->sz = p->sz;

  // copy saved user registers.
  *(np->trapframe) = *(p->trapframe);

  // Cause fork to return 0 in the child.
  np->trapframe->a0 = 0;
  if (child_stack != 0)
    np->trapframe->sp = child_stack;

  copy_linux_state(np, p);
  np->linux_ppid_override = 0;
  if (p->contest_role == CONTEST_ROLE_LIBCTEST_MUSL &&
      p->contest_owner && p->pid == 1)
    np->linux_ppid_override = p->pid + 1000;

