static int
ext4_name_match(const uchar *entry_name, uint entry_len, const char *want,
                uint want_len)
{
  if (entry_len != want_len)
    return 0;
  return memcmp(entry_name, want, want_len) == 0;
}

static int
ext4_dir_lookup(const struct ext4_lite_inode *dir, const char *name, uint len,
                struct ext4_lite_inode *out)
{
  if ((dir->mode & EXT4_S_IFMT) != EXT4_S_IFDIR || len > EXT4_MAX_NAME_LEN)
    return -1;

  uchar *block = kalloc();
  if (block == 0)
    return -1;

  for (uint64 off = 0; off < dir->size; off += ext4.block_size) {
    uint logical = off / ext4.block_size;
    if (ext4_read_inode_block(dir, logical, block) < 0) {
      kfree(block);
      return -1;
    }

    uint inblock = 0;
    while (inblock + 8 <= ext4.block_size && off + inblock < dir->size) {
      uchar *de = block + inblock;
      uint inum = get32(de + 0x00);
      uint rec_len = get16(de + 0x04);
      uint name_len = de[6];
      if (rec_len < 8 || rec_len > ext4.block_size - inblock ||
          name_len > rec_len - 8) {
        kfree(block);
        return -1;
      }

      if (inum != 0 && ext4_name_match(de + 8, name_len, name, len)) {
        kfree(block);
        return ext4_read_inode(inum, out);
      }

      inblock += rec_len;
    }
  }

  kfree(block);
  return -1;
}

int
ext4_lite_lookup_path(const char *path, struct ext4_lite_inode *out)
{
  if (ext4_mount() < 0 || path == 0 || path[0] != '/')
    return -1;

  struct ext4_lite_inode cur;
  if (ext4_read_inode(EXT4_ROOT_INO, &cur) < 0)
    return -1;

  const char *p = path;
  while (*p == '/')
    p++;
  if (*p == 0) {
    *out = cur;
    return 0;
  }

  while (*p) {
    const char *start = p;
    uint len = 0;
    while (p[len] && p[len] != '/')
      len++;
    if (len == 0 || len > EXT4_MAX_NAME_LEN)
      return -1;

    struct ext4_lite_inode next;
    if (ext4_dir_lookup(&cur, start, len, &next) < 0)
      return -1;
    cur = next;

    p += len;
    while (*p == '/')
      p++;
  }

  *out = cur;
  return 0;
}

int
ext4_lite_read_file(const char *path, uint off, void *dst, uint n)
{
  struct ext4_lite_inode ino;
  if (ext4_lite_lookup_path(path, &ino) < 0)
    return -1;
  if ((ino.mode & EXT4_S_IFMT) != EXT4_S_IFREG)
    return -1;
  return ext4_read_inode_data(&ino, off, dst, n);
}

static int
ext4_require_path(const char *path, ushort type, struct ext4_lite_inode *out)
{
  if (ext4_lite_lookup_path(path, out) < 0) {
    printf("ext4: missing %s\n", path);
    return -1;
  }
  if ((out->mode & EXT4_S_IFMT) != type) {
    printf("ext4: wrong type for %s mode=0x%x\n", path, out->mode);
    return -1;
  }
  return 0;
}

int
ext4_lite_probe(void)
{
  printf("A1 ext4 probe: start\n");

  if (ext4_mount() < 0)
    return -1;

  struct ext4_lite_inode root;
  struct ext4_lite_inode musl;
  struct ext4_lite_inode basic;
  struct ext4_lite_inode brk;

  if (ext4_require_path("/", EXT4_S_IFDIR, &root) < 0)
    return -1;
  if (ext4_require_path("/musl", EXT4_S_IFDIR, &musl) < 0)
    return -1;
  if (ext4_require_path("/glibc", EXT4_S_IFDIR, &root) < 0)
    return -1;
  printf("ext4: / entries include: glibc musl\n");

  if (ext4_require_path("/musl/basic", EXT4_S_IFDIR, &basic) < 0)
    return -1;
  if (ext4_require_path("/musl/basic/brk", EXT4_S_IFREG, &brk) < 0)
    return -1;
  if (ext4_lite_lookup_path("/musl/basic/chdir", &root) < 0 ||
      ext4_lite_lookup_path("/musl/basic/clone", &root) < 0) {
    printf("ext4: /musl/basic missing expected sample entries\n");
    return -1;
  }
  printf("ext4: /musl/basic entries include: brk chdir clone\n");
  printf("ext4: /musl/basic/brk size=%lu\n", brk.size);

  uchar elf[4];
  int n = ext4_lite_read_file("/musl/basic/brk", 0, elf, sizeof(elf));
  if (n != sizeof(elf) || elf[0] != 0x7f || elf[1] != 'E' || elf[2] != 'L' ||
      elf[3] != 'F') {
    printf("ext4: /musl/basic/brk ELF header check failed\n");
    return -1;
  }
  printf("ext4: /musl/basic/brk elf_magic=0x%x%x%x%x\n", elf[0], elf[1],
         elf[2], elf[3]);

  printf("A1 ext4 probe: ok\n");
  return 0;
}

linux_sys_openat(void)
{
  int dirfd = (int)linux_argraw(0);
  uint64 path_addr = linux_argraw(1);
  int flags = (int)linux_argraw(2);
  char path[MAXPATH];
  char resolved[MAXPATH];
  struct linux_fd fd;
  int tmp_index = -1;
  int existed_tmp = 0;
  int found_ext4;

  if (copyinstr(myproc()->pagetable, path, path_addr, sizeof(path)) < 0)
    return -LINUX_EFAULT;
  int rc = linux_resolve_path(dirfd, path, resolved);
  if (rc < 0)
    return rc;

  memset(&fd, 0, sizeof(fd));
  found_ext4 = ext4_lite_lookup_path(resolved, &fd.ino) == 0;
  if (!found_ext4) {
    tmp_index = linux_tmp_find(resolved, 0);
    if (tmp_index < 0 && linux_dev_virtual_file(resolved))
      tmp_index = linux_dev_materialize_file(resolved);
    if (tmp_index < 0 && linux_proc_virtual_file(resolved))
      tmp_index = linux_proc_materialize_file(resolved);
    if (tmp_index < 0 && linux_proc_virtual_dir(resolved))
      tmp_index = linux_proc_materialize_dir(resolved);
    if (tmp_index < 0 && linux_tmp_virtual_dir(resolved))
      tmp_index = linux_tmp_materialize_dir(resolved);
    if (tmp_index < 0 && (flags & LINUX_O_DIRECTORY))
      tmp_index = linux_tmp_find(resolved, 1);
    existed_tmp = tmp_index >= 0;
    if (tmp_index < 0 && (flags & LINUX_O_CREAT) == 0)
      return -LINUX_ENOENT;
    if (tmp_index < 0 && !linux_path_parent_dir_exists(resolved))
      return -LINUX_ENOENT;
    if (tmp_index < 0)
      tmp_index = linux_tmp_add(resolved, 0);
    if (tmp_index < 0)
      return -LINUX_ENOMEM;
    memset(&fd.ino, 0, sizeof(fd.ino));
    struct linux_tmp_path *tmp = linux_tmp_get(tmp_index);
    if ((flags & LINUX_O_EXCL) && existed_tmp && tmp && !tmp->is_dir)
      return -LINUX_EEXIST;
    fd.ino.mode = tmp ? linux_tmp_mode(resolved, tmp->is_dir) : 0100644;
    fd.ino.nlink = 1;
    fd.type = tmp && tmp->is_dir ? LINUX_FD_TMP_DIR : LINUX_FD_TMP_FILE;
    fd.tmp_index = tmp_index;
  } else {
    fd.type = linux_fd_type_from_inode(&fd.ino);
    fd.tmp_index = -1;
  }
  if (fd.type < 0)
    return -LINUX_ENODEV;
  if (flags & LINUX_O_DIRECTORY) {
    if (fd.type != LINUX_FD_EXT4_DIR && fd.type != LINUX_FD_TMP_DIR)
      return -LINUX_ENOTDIR;
  }
  fd.used = 1;
  fd.readable = 1;
  fd.writable = fd.type == LINUX_FD_TMP_FILE &&
                (flags & LINUX_O_ACCMODE) != 0;
  fd.off = 0;
  if (fd.type == LINUX_FD_TMP_FILE) {
    struct linux_tmp_path *tmp = linux_tmp_get(fd.tmp_index);
    if ((flags & LINUX_O_TRUNC) && fd.writable)
      tmp->size = 0;
    if (flags & LINUX_O_APPEND)
      fd.off = tmp->size;
  }
  safestrcpy(fd.path, resolved, sizeof(fd.path));
  return linux_fd_alloc(&fd);
}

static uint64
linux_sys_mkdirat(void)
{
  int dirfd = (int)linux_argraw(0);
  uint64 path_addr = linux_argraw(1);
  char path[MAXPATH];
  char resolved[MAXPATH];
  struct ext4_lite_inode ino;

  if (copyinstr(myproc()->pagetable, path, path_addr, sizeof(path)) < 0)
    return -LINUX_EFAULT;
  int rc = linux_resolve_path(dirfd, path, resolved);
  if (rc < 0)
    return rc;
  if (ext4_lite_lookup_path(resolved, &ino) == 0 || linux_tmp_lookup(resolved, 1))
    return -LINUX_EEXIST;
  if (linux_tmp_lookup(resolved, 0))
    return -LINUX_EEXIST;
  if (!linux_path_parent_dir_exists(resolved))
    return -LINUX_ENOENT;
  rc = linux_tmp_add(resolved, 1);
  return rc < 0 ? rc : 0;
}

static uint64
linux_sys_unlinkat(void)
{
  int dirfd = (int)linux_argraw(0);
  uint64 path_addr = linux_argraw(1);
  int flags = (int)linux_argraw(2);
  char path[MAXPATH];
  char resolved[MAXPATH];
  struct ext4_lite_inode ino;

  if (copyinstr(myproc()->pagetable, path, path_addr, sizeof(path)) < 0)
    return -LINUX_EFAULT;
  int rc = linux_resolve_path(dirfd, path, resolved);
  if (rc < 0)
    return rc;
  if (flags != 0 && flags != LINUX_AT_REMOVEDIR)
    return -LINUX_EINVAL;
  rc = linux_tmp_remove(resolved, (flags & LINUX_AT_REMOVEDIR) != 0);
  if (rc == 0)
    return 0;
  if (rc != -LINUX_ENOENT)
    return rc;
  if (ext4_lite_lookup_path(resolved, &ino) == 0)
    return -LINUX_EPERM;
  if (strncmp(resolved, LINUX_BASIC_DIR "/", strlen(LINUX_BASIC_DIR "/")) == 0)
    return 0;
  return -LINUX_ENOENT;
}

static uint64
linux_sys_faccessat(void)
