static struct linux_mount *
linux_mount_find(char *target)
{
  struct proc *p = myproc();

  for (int i = 0; i < LINUX_MAX_MOUNT; i++) {
    if (p->linux_mounts[i].used &&
        strncmp(p->linux_mounts[i].target, target, MAXPATH) == 0)
      return &p->linux_mounts[i];
  }
  return 0;
}

static struct linux_mount *
linux_mount_alloc(char *target)
{
  struct proc *p = myproc();
  struct linux_mount *existing = linux_mount_find(target);

  if (existing)
    return existing;
  for (int i = 0; i < LINUX_MAX_MOUNT; i++) {
    if (!p->linux_mounts[i].used)
      return &p->linux_mounts[i];
  }
  return 0;
}

static uint64
linux_sys_mount(void)
{
  uint64 source_addr = linux_argraw(0);
  uint64 target_addr = linux_argraw(1);
  uint64 fstype_addr = linux_argraw(2);
  char source[MAXPATH];
  char fstype[16];
  char target[MAXPATH];
  struct linux_mount *mnt;

  if (copyinstr(myproc()->pagetable, source, source_addr, sizeof(source)) < 0)
    return -LINUX_EFAULT;
  if (fstype_addr != 0) {
    if (copyinstr(myproc()->pagetable, fstype, fstype_addr,
                  sizeof(fstype)) < 0)
      return -LINUX_EFAULT;
  } else {
    fstype[0] = 0;
  }

  int rc = linux_mount_resolve_target(target_addr, target);
  if (rc < 0)
    return rc;
  if (!linux_mount_is_basic_mnt(target))
    return -LINUX_EINVAL;

  mnt = linux_mount_alloc(target);
  if (mnt == 0)
    return -LINUX_ENOMEM;
  memset(mnt, 0, sizeof(*mnt));
  mnt->used = 1;
  safestrcpy(mnt->target, target, sizeof(mnt->target));
  safestrcpy(mnt->source, source, sizeof(mnt->source));
  safestrcpy(mnt->fstype, fstype, sizeof(mnt->fstype));
  return 0;
}

static uint64
linux_sys_umount2(void)
{
  char target[MAXPATH];
  int rc = linux_mount_resolve_target(linux_argraw(0), target);

  if (rc < 0)
    return rc;
  struct linux_mount *mnt = linux_mount_find(target);
  if (mnt != 0) {
    memset(mnt, 0, sizeof(*mnt));
    return 0;
  }
  if (linux_mount_is_basic_mnt(target))
    return 0;
  return -LINUX_EINVAL;
}

static int
linux_mmap_vma_overlaps(uint64 addr, uint64 len)
{
  struct proc *p = myproc();
  uint64 end = addr + len;

  if (end < addr || end >= TRAPFRAME)
    return 1;
  for (int i = 0; i < LINUX_MAX_VMA; i++) {
    if (!p->linux_vmas[i].used)
      continue;
    uint64 vma_end = p->linux_vmas[i].addr + p->linux_vmas[i].len;
    if (addr < vma_end && p->linux_vmas[i].addr < end)
      return 1;
  }
  for (uint64 a = addr; a < end; a += PGSIZE) {
    if (ismapped(p->pagetable, a))
      return 1;
  }
  return 0;
}

static uint64
linux_mmap_pick_addr(uint64 len)
{
  struct proc *p = myproc();
  uint64 addr = LINUX_MMAP_BASE;
  int changed;

  do {
    changed = 0;
    for (int i = 0; i < LINUX_MAX_VMA; i++) {
      if (!p->linux_vmas[i].used)
        continue;
      uint64 vma_end = p->linux_vmas[i].addr + p->linux_vmas[i].len;
      if (addr + len > p->linux_vmas[i].addr && addr < vma_end) {
        addr = PGROUNDUP(vma_end);
        changed = 1;
      }
    }
  } while (changed);

  if (linux_mmap_vma_overlaps(addr, len))
    return 0;
  return addr;
}

static struct linux_vma *
linux_mmap_alloc_vma(void)
{
  struct proc *p = myproc();

  for (int i = 0; i < LINUX_MAX_VMA; i++) {
    if (!p->linux_vmas[i].used)
      return &p->linux_vmas[i];
  }
  return 0;
}

static int
linux_mmap_pte_perm(int prot)
{
  int perm = PTE_U;

  if (prot & (LINUX_PROT_READ | LINUX_PROT_WRITE))
    perm |= PTE_R;
  if (prot & LINUX_PROT_WRITE)
    perm |= PTE_W;
  if (prot & LINUX_PROT_EXEC)
    perm |= PTE_X;
  if ((perm & (PTE_R | PTE_W | PTE_X)) == 0)
    perm |= PTE_R;
  return perm;
}

static int
linux_mmap_map_pages(uint64 addr, uint64 len, int perm)
{
  struct proc *p = myproc();
  uint64 mapped = 0;

  while (mapped < len) {
    char *mem = kalloc();
    if (mem == 0)
      goto bad;
    memset(mem, 0, PGSIZE);
    if (mappages(p->pagetable, addr + mapped, PGSIZE, (uint64)mem, perm) < 0) {
      kfree(mem);
      goto bad;
    }
    mapped += PGSIZE;
  }
  return 0;

bad:
  if (mapped > 0)
    uvmunmap(p->pagetable, addr, mapped / PGSIZE, 1);
  return -LINUX_ENOMEM;
}

static int
linux_mmap_load_file(struct linux_fd *fd, uint64 dst, uint64 len,
                     uint64 offset)
{
  struct proc *p = myproc();

  if (fd->type == LINUX_FD_TMP_FILE) {
    struct linux_tmp_path *tmp = linux_tmp_get(fd->tmp_index);
    uint take;

    if (tmp == 0 || tmp->is_dir)
      return -LINUX_EBADF;
    if (offset >= tmp->size)
      return 0;
    take = tmp->size - offset;
    if (take > len)
      take = len;
    if (copyout(p->pagetable, dst, (char *)tmp->data + offset, take) < 0)
      return -LINUX_EFAULT;
    return 0;
  }

  if (fd->type != LINUX_FD_EXT4_FILE)
    return -LINUX_EBADF;

  uchar *buf = kalloc();
  if (buf == 0)
    return -LINUX_ENOMEM;

  uint64 done = 0;
  while (done < len) {
    uint take = len - done < PGSIZE ? len - done : PGSIZE;
    if (offset + done > 0xffffffffULL) {
      kfree(buf);
      return -LINUX_EINVAL;
    }
    int r = ext4_lite_read_inode_data(&fd->ino, (uint)(offset + done),
                                      buf, take);
    if (r < 0) {
      kfree(buf);
      return -LINUX_EIO;
    }
    if (r == 0)
      break;
    if (copyout(p->pagetable, dst + done, (char *)buf, r) < 0) {
      kfree(buf);
      return -LINUX_EFAULT;
    }
    done += r;
    if ((uint)r < take)
      break;
  }

  kfree(buf);
  return 0;
}

static uint64
linux_sys_mmap(void)
{
  uint64 addr = linux_argraw(0);
  uint64 length = linux_argraw(1);
  int prot = (int)linux_argraw(2);
  int flags = (int)linux_argraw(3);
  int fdno = (int)linux_argraw(4);
  uint64 offset = linux_argraw(5);
  struct linux_fd *fd = 0;
  struct linux_vma *vma;

  if (length == 0)
    return -LINUX_EINVAL;
  uint64 map_len = PGROUNDUP(length);
  if (map_len == 0 || map_len < length)
    return -LINUX_EINVAL;
  if (offset % PGSIZE != 0)
    return -LINUX_EINVAL;

  if ((flags & LINUX_MAP_ANONYMOUS) == 0) {
    fd = linux_fd_get(fdno);
    if (fd == 0)
      return -LINUX_EBADF;
    if (fd->type != LINUX_FD_EXT4_FILE && fd->type != LINUX_FD_TMP_FILE)
      return -LINUX_EBADF;
  }

  if (addr == 0) {
    addr = linux_mmap_pick_addr(map_len);
    if (addr == 0)
      return -LINUX_ENOMEM;
  } else {

  } else {
    if (addr % PGSIZE != 0 || linux_mmap_vma_overlaps(addr, map_len))
      return -LINUX_EINVAL;
  }

  vma = linux_mmap_alloc_vma();
  if (vma == 0)
    return -LINUX_ENOMEM;
  int rc = linux_mmap_map_pages(addr, map_len, linux_mmap_pte_perm(prot));
  if (rc < 0)
    return rc;

  if (fd != 0) {
    rc = linux_mmap_load_file(fd, addr, length, offset);
    if (rc < 0) {
      uvmunmap(myproc()->pagetable, addr, map_len / PGSIZE, 1);
      return rc;
    }
  }

  memset(vma, 0, sizeof(*vma));
  vma->used = 1;
  vma->addr = addr;
  vma->len = map_len;
  vma->prot = prot;
  vma->flags = flags;
  vma->fd = fdno;
  return addr;
}

static uint64
linux_sys_munmap(void)
{
  uint64 addr = linux_argraw(0);
  uint64 length = linux_argraw(1);

  if (length == 0 || addr % PGSIZE != 0)
    return -LINUX_EINVAL;
  uint64 map_len = PGROUNDUP(length);
  if (map_len == 0 || map_len < length)
    return -LINUX_EINVAL;

  struct proc *p = myproc();
  for (int i = 0; i < LINUX_MAX_VMA; i++) {
    struct linux_vma *vma = &p->linux_vmas[i];
    if (!vma->used)
      continue;
    if (vma->addr == addr && vma->len == map_len) {
      uvmunmap(p->pagetable, addr, map_len / PGSIZE, 1);
      memset(vma, 0, sizeof(*vma));
      return 0;
    }
  }

  return -LINUX_EINVAL;
}

static char *
linux_sys_basename(char *path)
{
  char *base = path;

  for (char *p = path; *p; p++) {
    if (*p == '/' && p[1])
      base = p + 1;
  }

  return base;
}

static int
linux_has_slash(char *path)
{
  for (char *p = path; *p; p++) {
    if (*p == '/')
      return 1;
  }
  return 0;
}


static int
linux_is_busybox_applet(char *name)
{
  char *applets[] = {
    "ash", "sh", "echo", "pwd", "uname", "basename",
    "dirname", "ls", "cat", "touch", "rm", "mkdir",
    "mv", "rmdir", "cut", "head", "tail", "sort",
    "uniq", "stat", "strings", "wc", "more", "grep",
    "cp", "find", "false", "which", "od", "hexdump",
    "md5sum", "cal", "clear", "date", "df", "dmesg",
    "uptime", "free", "kill", 0
  };

  for (int i = 0; applets[i]; i++) {
    if (strncmp(name, applets[i], MAXPATH) == 0)
      return 1;
  }
  return 0;
}

static int
linux_busybox_virtual_applet(char *path)
{
  if (!linux_role_is_busybox(myproc()->contest_role))
    return 0;
  return linux_is_busybox_applet(linux_sys_basename(path));
}

static int
linux_resolve_busybox_exec_path(char *path, char *out)
{
  char *name = linux_sys_basename(path);

  if (strncmp(name, "busybox", MAXPATH) == 0 ||
      linux_is_busybox_applet(name)) {
    safestrcpy(out, linux_busybox_binary(), MAXPATH);
    return 0;
  }
  return -LINUX_ENOENT;
}

static int
linux_resolve_basic_exec_path(char *path, char *out)
{
  char *name = path;

  if (path[0] == '/') {
    if (strncmp(path, LINUX_BASIC_DIR "/", strlen(LINUX_BASIC_DIR "/")) != 0)
      return -LINUX_ENOENT;
    safestrcpy(out, path, MAXPATH);
    return 0;
  }

  if (path[0] == '.' && path[1] == '/')
    name = path + 2;
  if (name[0] == 0 || linux_has_slash(name))
    return -LINUX_ENOENT;

  int prefix_len = strlen(LINUX_BASIC_DIR "/");
  int name_len = strlen(name);
  if (prefix_len + name_len >= MAXPATH)
    return -LINUX_ENOENT;

  safestrcpy(out, LINUX_BASIC_DIR "/", MAXPATH);
  safestrcpy(out + prefix_len, name, MAXPATH - prefix_len);
  return 0;
}

static int
linux_copy_exec_argv(uint64 uargv,
                     char argv_store[LINUX_EXEC_MAX_ARGC][LINUX_EXEC_MAX_ARG_BYTES],
                     char **kargv)
{
  struct proc *p = myproc();
  int i;

  memset(argv_store, 0,
         LINUX_EXEC_MAX_ARGC * LINUX_EXEC_MAX_ARG_BYTES);
  for (i = 0; i <= LINUX_EXEC_MAX_ARGC; i++)
    kargv[i] = 0;

  if (uargv == 0)
    return 0;

  for (i = 0; i < LINUX_EXEC_MAX_ARGC; i++) {
    uint64 up;
    if (copyin(p->pagetable, (char *)&up,
               uargv + i * sizeof(uint64), sizeof(up)) < 0)
      return -LINUX_EFAULT;
    if (up == 0)
      return 0;
    if (copyinstr(p->pagetable, argv_store[i], up,
                  LINUX_EXEC_MAX_ARG_BYTES) < 0)
      return -LINUX_EFAULT;
    kargv[i] = argv_store[i];
  }

  uint64 extra;
  if (copyin(p->pagetable, (char *)&extra,
             uargv + LINUX_EXEC_MAX_ARGC * sizeof(uint64),
             sizeof(extra)) < 0)
    return -LINUX_EFAULT;
  if (extra != 0)
    return -LINUX_EINVAL;
  return 0;
}

static uint64
linux_sys_execve(void)
{
  struct proc *p = myproc();
  char path[MAXPATH];
  char resolved[MAXPATH];
  char display[32];
  char argv_store[LINUX_EXEC_MAX_ARGC][LINUX_EXEC_MAX_ARG_BYTES];
  char *kargv[LINUX_EXEC_MAX_ARGC + 1];
  int rc;

  if (copyinstr(p->pagetable, path, linux_argraw(0), sizeof(path)) < 0)
    return -LINUX_EFAULT;

  if (linux_role_is_busybox(p->contest_role))
    rc = linux_resolve_busybox_exec_path(path, resolved);
  else
    rc = linux_resolve_basic_exec_path(path, resolved);
  if (rc < 0)
    return rc;

  rc = linux_copy_exec_argv(linux_argraw(1), argv_store, kargv);
  if (rc < 0)
    return rc;

  if (p->contest_role == CONTEST_ROLE_BASIC_MUSL &&
      p->contest_test_name[0] != 0)
    safestrcpy(display, p->contest_test_name, sizeof(display));
  else
    safestrcpy(display, linux_sys_basename(resolved), sizeof(display));

  if (linux_exec_ext4(resolved, kargv, p->contest_role, display) < 0)
    return -LINUX_ENOENT;

  return 0;
}

static uint64
linux_sys_exit(void)
{
  struct proc *p = myproc();
  int status = (int)linux_argraw(0);

  if ((p->contest_role == CONTEST_ROLE_BASIC_MUSL ||
       linux_role_is_busybox(p->contest_role) ||
       p->contest_role == CONTEST_ROLE_LIBCTEST_MUSL ||
       p->contest_role == CONTEST_ROLE_LIBCTEST_DYNAMIC_MUSL ||
       p->contest_role == CONTEST_ROLE_LUA_MUSL) &&
      p->contest_owner) {
    contest_runner_finish(status);
    return 0;
  }

  kexit(status);
  return 0;
}

