void
contest_runner_finish(int status)
{
#if CONTEST_RUNNER
  struct proc *p = myproc();
  int next;

  if (contest_runner_role_is_busybox(p->contest_role)) {
    char *group = contest_runner_busybox_group(p->contest_role);
    int ok = status == 0 ||
             strncmp(p->contest_test_name, "false",
                     sizeof(p->contest_test_name)) == 0;
    printf("testcase busybox %s %s\n", p->contest_test_name,
           ok ? "success" : "fail");

    next = p->contest_index + 1;
    int rc = contest_runner_run_busybox_index(next, p->contest_role);
    if (rc == 0)
      return;

    printf("#### OS COMP TEST GROUP END %s ####\n", group);
    if (p->contest_role == CONTEST_ROLE_BUSYBOX_MUSL) {
      int a4rc = contest_runner_start_a4();
      if (a4rc == 0)
        return;
      sbi_shutdown((!ok) || rc < 0 || a4rc < 0);
    } else {
      sbi_shutdown((!ok) || rc < 0);
    }
    panic("contest runner shutdown failed");
  }

  if (p->contest_role == CONTEST_ROLE_LIBCTEST_MUSL) {
    if (status == 0)
      printf("Pass!\n");
    printf("========== END %s ==========\n", p->contest_test_name);

    next = p->contest_index + 1;
    int rc = contest_runner_run_libctest_static_index(next);
    if (rc == 0)
      return;

    printf("#### OS COMP TEST GROUP END libctest-musl ####\n");
    int nextrc = contest_runner_start_after_libctest();
    if (nextrc == 0)
      return;
    sbi_shutdown(status != 0 || rc < 0 || nextrc < 0);
    panic("contest runner shutdown failed");
  }

  if (p->contest_role == CONTEST_ROLE_LIBCTEST_DYNAMIC_MUSL) {
    if (status == 0)
      printf("Pass!\n");
    printf("========== END %s ==========\n", p->contest_test_name);

    next = p->contest_index + 1;
    int rc = contest_runner_run_libctest_dynamic_index(next);
    if (rc == 0)
      return;

    printf("#### OS COMP TEST GROUP END libctest-musl ####\n");
    int nextrc = A4_LUA_LIMIT > 0 ? contest_runner_start_lua() :
                                      contest_runner_start_after_a4();
    if (nextrc == 0)
      return;
    sbi_shutdown(status != 0 || rc < 0 || nextrc < 0);
    panic("contest runner shutdown failed");
  }

  if (p->contest_role == CONTEST_ROLE_LUA_MUSL) {
    int ok = status == 0;
    printf("testcase lua %s %s\n", p->contest_test_name,
           ok ? "success" : "fail");

    next = p->contest_index + 1;
    int rc = contest_runner_run_lua_index(next);
    if (rc == 0)
      return;

    printf("#### OS COMP TEST GROUP END lua-musl ####\n");
    int nextrc = contest_runner_start_after_a4();
    if (nextrc == 0)
      return;
    sbi_shutdown((!ok) || rc < 0 || nextrc < 0);
    panic("contest runner shutdown failed");
  }

  printf("========== END %s ==========\n", p->contest_test_name);

  next = p->contest_index + 1;
  int rc = contest_runner_run_index(next);
  if (rc == 0)
    return;

  printf("#### OS COMP TEST GROUP END basic-musl ####\n");
  if (status != 0 || rc < 0 ||
      contest_runner_start_busybox(CONTEST_ROLE_BUSYBOX_MUSL) < 0) {
    sbi_shutdown(1);
    panic("contest runner shutdown failed");
  }
  return;
#else
  sbi_shutdown(status != 0);
  panic("contest runner shutdown failed");
#endif
}

