static uint64
linux_sys_close(void)
{
  int fd = (int)linux_argraw(0);

  if (linux_fd_get(fd) == 0)
    return -LINUX_EBADF;
  linux_fd_close(fd);
  return 0;
}

static uint64
linux_sys_dup(void)
{
  int oldfd = (int)linux_argraw(0);
  struct linux_fd *src = linux_fd_get(oldfd);
  struct linux_fd copy;
  int fd;

  if (src == 0)
    return -LINUX_EBADF;
  copy = *src;
  if (copy.xv6_file)
    copy.xv6_file = filedup(copy.xv6_file);
  fd = linux_fd_alloc(&copy);
  if (fd < 0 && copy.xv6_file)
    fileclose(copy.xv6_file);
  return fd;
}

static uint64
linux_sys_dup3(void)
{
  int oldfd = (int)linux_argraw(0);
  int newfd = (int)linux_argraw(1);
  int flags = (int)linux_argraw(2);

  if (flags != 0)
    return -LINUX_EINVAL;
  return linux_fd_dup_to(oldfd, newfd);
}

static uint64
linux_sys_fcntl(void)
{
  int fdno = (int)linux_argraw(0);
  int cmd = (int)linux_argraw(1);
  int arg = (int)linux_argraw(2);
  struct linux_fd *fd = linux_fd_get(fdno);
  struct linux_fd copy;

  if (fd == 0)
    return -LINUX_EBADF;

  switch (cmd) {
  case LINUX_F_DUPFD:
  case LINUX_F_DUPFD_CLOEXEC:
    copy = *fd;
    if (copy.xv6_file)
      copy.xv6_file = filedup(copy.xv6_file);
    int newfd = linux_fd_alloc_from(&copy, arg);
    if (newfd < 0 && copy.xv6_file)
      fileclose(copy.xv6_file);
    return newfd;
  case LINUX_F_GETFD:
    return 0;
  case LINUX_F_SETFD:
    return 0;
  case LINUX_F_GETFL:
    return (fd->readable && fd->writable) ? 2 : (fd->writable ? 1 : 0);
  case LINUX_F_SETFL:
    return 0;
  default:
    return -LINUX_EINVAL;
  }
}

