linux_sys_getrandom(void)
{
  uint64 buf_addr = linux_argraw(0);
  uint64 len = linux_argraw(1);
  char buf[32];
  uint64 done = 0;

  while (done < len) {
    uint64 n = len - done;
    if (n > sizeof(buf))
      n = sizeof(buf);
    for (uint64 i = 0; i < n; i++)
      buf[i] = (char)(0xa5 ^ (myproc()->pid + done + i));
    if (copyout(myproc()->pagetable, buf_addr + done, buf, n) < 0)
      return -LINUX_EFAULT;
    done += n;
  }
  return len;
}

