static int
linux_tmp_apply_times(struct linux_tmp_path *tmp, uint64 times_addr)
{
  struct linux_timespec ts[2];
  long now_sec;
  uint64 now_nsec;
  int changed = 0;

  if (times_addr == 0) {
    linux_now_timespec(&now_sec, &now_nsec);
    tmp->atime_sec = now_sec;
    tmp->atime_nsec = now_nsec;
    tmp->mtime_sec = now_sec;
    tmp->mtime_nsec = now_nsec;
    tmp->ctime_sec = now_sec;
    tmp->ctime_nsec = now_nsec;
    return 0;
  }

  if (copyin(myproc()->pagetable, (char *)ts, times_addr, sizeof(ts)) < 0)
    return -LINUX_EFAULT;
  for (int i = 0; i < 2; i++) {
    if (ts[i].tv_nsec != LINUX_UTIME_NOW &&
        ts[i].tv_nsec != LINUX_UTIME_OMIT &&
        ts[i].tv_nsec >= 1000000000ULL)
      return -LINUX_EINVAL;
  }

  if (ts[0].tv_nsec != LINUX_UTIME_OMIT) {
    if (ts[0].tv_nsec == LINUX_UTIME_NOW) {
      linux_now_timespec(&tmp->atime_sec, &tmp->atime_nsec);
    } else {
      tmp->atime_sec = ts[0].tv_sec;
      tmp->atime_nsec = ts[0].tv_nsec;
    }
    changed = 1;
  }
  if (ts[1].tv_nsec != LINUX_UTIME_OMIT) {
    if (ts[1].tv_nsec == LINUX_UTIME_NOW) {
      linux_now_timespec(&tmp->mtime_sec, &tmp->mtime_nsec);
    } else {
      tmp->mtime_sec = ts[1].tv_sec;
      tmp->mtime_nsec = ts[1].tv_nsec;
    }
    changed = 1;
  }
  if (changed)
    linux_now_timespec(&tmp->ctime_sec, &tmp->ctime_nsec);
  return 0;
}

