static int
linux_rlimit_valid_resource(int resource)
{
  return resource >= 0 && resource < LINUX_RLIMIT_NLIMITS;
}

static void
linux_rlimit_get(int resource, struct linux_rlimit *limit)
{
  struct proc *p = myproc();

  switch (resource) {
  case LINUX_RLIMIT_NOFILE:
    limit->rlim_cur = p->linux_rlimit_nofile_cur;
    limit->rlim_max = p->linux_rlimit_nofile_max;
    break;
  case LINUX_RLIMIT_STACK:
    limit->rlim_cur = p->linux_rlimit_stack_cur;
    limit->rlim_max = p->linux_rlimit_stack_max;
    break;
  default:
    limit->rlim_cur = LINUX_RLIM_INFINITY;
    limit->rlim_max = LINUX_RLIM_INFINITY;
    break;
  }
}

static int
linux_rlimit_set(int resource, struct linux_rlimit *limit)
{
  struct proc *p = myproc();

  if (!linux_rlimit_valid_resource(resource))
    return -LINUX_EINVAL;
  if (limit->rlim_cur > limit->rlim_max)
    return -LINUX_EINVAL;

  switch (resource) {
  case LINUX_RLIMIT_NOFILE:
    if (limit->rlim_max > LINUX_NOFILE)
      return -LINUX_EPERM;
    p->linux_rlimit_nofile_cur = limit->rlim_cur;
    p->linux_rlimit_nofile_max = limit->rlim_max;
    break;
  case LINUX_RLIMIT_STACK:
    p->linux_rlimit_stack_cur = limit->rlim_cur;
    p->linux_rlimit_stack_max = limit->rlim_max;
    break;
  default:
    break;
  }
  return 0;
}

static uint64
linux_sys_getrlimit(void)
{
  int resource = (int)linux_argraw(0);
  uint64 limit_addr = linux_argraw(1);
  struct linux_rlimit limit;

  if (!linux_rlimit_valid_resource(resource))
    return -LINUX_EINVAL;
  if (limit_addr == 0)
    return -LINUX_EFAULT;

  linux_rlimit_get(resource, &limit);
  if (copyout(myproc()->pagetable, limit_addr, (char *)&limit,
              sizeof(limit)) < 0)
    return -LINUX_EFAULT;
  return 0;
}

static uint64
linux_sys_setrlimit(void)
{
  int resource = (int)linux_argraw(0);
  uint64 limit_addr = linux_argraw(1);
  struct linux_rlimit limit;

  if (limit_addr == 0)
    return -LINUX_EFAULT;
  if (copyin(myproc()->pagetable, (char *)&limit, limit_addr,
             sizeof(limit)) < 0)
    return -LINUX_EFAULT;
  return linux_rlimit_set(resource, &limit);
}

static uint64
linux_sys_prlimit64(void)
{
  int pid = (int)linux_argraw(0);
  int resource = (int)linux_argraw(1);
  uint64 new_limit_addr = linux_argraw(2);
  uint64 old_limit_addr = linux_argraw(3);
  struct proc *p = myproc();
  struct linux_rlimit old_limit;
  struct linux_rlimit new_limit;

  if (pid != 0 && pid != p->pid)
    return -LINUX_EINVAL;
  if (!linux_rlimit_valid_resource(resource))
    return -LINUX_EINVAL;

  if (old_limit_addr != 0) {
    linux_rlimit_get(resource, &old_limit);
    if (copyout(p->pagetable, old_limit_addr, (char *)&old_limit,
                sizeof(old_limit)) < 0)
      return -LINUX_EFAULT;
  }

  if (new_limit_addr == 0)
    return 0;
  if (copyin(p->pagetable, (char *)&new_limit, new_limit_addr,
             sizeof(new_limit)) < 0)
    return -LINUX_EFAULT;
  return linux_rlimit_set(resource, &new_limit);
}

